# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, redirect, session, url_for, request, jsonify
import requests
import jwt

app = Flask(__name__)
app.secret_key = 'your_secret_key'
client_id = 'your_client_id'
client_secret = 'your_client_secret'
redirect_uri = 'http://localhost:5000/callback'
authorization_endpoint = 'https://provider.com/authorize'
token_endpoint = 'https://provider.com/token'
issuer = 'https://provider.com'
scope = 'openid profile email'

@app.route('/')
def index():
    return 'Welcome to the Flask OpenID Connect App'

@app.route('/login')
def login():
    auth_url = f"{authorization_endpoint}?response_type=code&client_id={client_id}&redirect_uri={redirect_uri}&scope={scope}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_response = requests.post(token_endpoint, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': redirect_uri,
        'client_id': client_id,
        'client_secret': client_secret
    })
    tokens = token_response.json()
    id_token = tokens['id_token']
    decoded_id_token = jwt.decode(id_token, options={"verify_signature": False}, audience=client_id)

    session['user'] = {
        'sub': decoded_id_token['sub'],
        'name': decoded_id_token['name'],
        'email': decoded_id_token['email']
    }
    return redirect(url_for('profile'))

@app.route('/profile')
def profile():
    user_info = session.get('user')
    if user_info:
        return jsonify(user_info)
    return redirect(url_for('login'))

@app.route('/logout')
def logout():
    session.pop('user', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)